frappe.ui.form.on("Library Member", {
    refresh(frm) {
        // Default values for new records
        if (frm.is_new()) {

            if (!frm.doc.membership_status) {
                frm.set_value("membership_status", "Active");
            }

            if (!frm.doc.membership_start) {
                frm.set_value("membership_start", frappe.datetime.get_today());
            }

            if (!frm.doc.membership_end) {
                frm.set_value(
                    "membership_end",
                    frappe.datetime.add_years(frappe.datetime.get_today(), 1)
                );
            }
        }
    },

    member_type(frm) {
        // Default maximum books
        if (frm.doc.member_type === "Student") {
            frm.set_value("max_books_allowed", 3);
        } else if (frm.doc.member_type === "Staff") {
            frm.set_value("max_books_allowed", 5);
        } else if (frm.doc.member_type === "Faculty") {
            frm.set_value("max_books_allowed", 10);
        }
    },

    student(frm) {

        if (!frm.doc.student) return;

        frappe.db.get_doc("Custom Student", frm.doc.student).then(doc => {

            frm.set_value("member_name", doc.student_name);
            frm.set_value("member_id", doc.name);

            frm.set_value("academic_year", doc.current_academic_year);

            frm.set_value("email", doc.student_email_id);

            frm.set_value("phone", doc.student_mobile_number);

            frm.set_value("current_program", doc.current_program);

        });

    }
});
